/**
 * Regression test for: Non-legacy mail content fails to decrypt
 *
 * Issue: When loading non-legacy mails with owner-encrypted session keys,
 * the session key from the parent mail object is not propagated to related
 * entity loading (MailDetailsBlob, MailDetailsDraft, etc.), causing
 * decryption failures with "Missing decryption key" errors.
 */

import { loadMailDetails } from "../app/src/mail/model/MailUtils"
import { EntityClient } from "../app/src/api/common/EntityClient"
import {
	createMail,
	createMailDetailsBlob,
	createMailDetails,
	createMailBody,
	MailBodyTypeRef,
	MailDetailsTypeRef,
	MailDetailsBlobTypeRef,
	MailTypeRef,
} from "../app/src/api/entities/tutanota/TypeRefs"
import { SessionKeyNotFoundError } from "../app/src/api/common/error/SessionKeyNotFoundError"
import { ElementEntity, ListElementEntity } from "../app/src/api/common/EntityTypes"
import { NotFoundError } from "../app/src/api/common/error/RestError"
import { TypeRef, downcast } from "@tutao/tutanota-utils"
import { getListId, getElementId } from "../app/src/api/common/utils/EntityUtils"
import type { SomeEntity } from "../app/src/api/common/EntityTypes"
import type { BlobElementEntity } from "../app/src/api/common/EntityTypes"

/**
 * Mock EntityRestClient that simulates the bug:
 * When loadMultiple is called without an ownerKey parameter,
 * it fails to decrypt owner-encrypted entities because the
 * session key is not available.
 */
class BuggyEntityRestClientMock {
	private entities: Record<string, any> = {}
	private listEntities: Record<string, Record<string, any>> = {}
	private blobEntities: Record<string, Record<string, any>> = {}
	private ownerEncryptedEntities: Set<string> = new Set()

	constructor() {}

	addBlobInstance(instance: BlobElementEntity) {
		const listId = getListId(instance)
		const elementId = getElementId(instance)
		if (!this.blobEntities[listId]) {
			this.blobEntities[listId] = {}
		}
		this.blobEntities[listId][elementId] = instance
	}

	addListInstance(instance: ListElementEntity) {
		const listId = getListId(instance)
		const elementId = getElementId(instance)
		if (!this.listEntities[listId]) {
			this.listEntities[listId] = {}
		}
		this.listEntities[listId][elementId] = instance
	}

	addElementInstance(instance: ElementEntity) {
		this.entities[instance._id] = instance
	}

	markAsOwnerEncrypted(id: string) {
		this.ownerEncryptedEntities.add(id)
	}

	async load<T extends SomeEntity>(
		typeRef: TypeRef<T>,
		id: T["_id"],
		queryParameters?: Dict,
		extraHeaders?: Dict,
		ownerKey?: Aes128Key,
	): Promise<T> {
		if (id instanceof Array && id.length === 2) {
			const [listId, elementId] = id
			const entity = this.listEntities[listId]?.[elementId]
			if (!entity) throw new NotFoundError(`Not found: ${listId} ${elementId}`)

			// With ownerKey, decryption would succeed (simulated by returning the entity)
			if (ownerKey && this.ownerEncryptedEntities.has(elementId)) {
				return entity
			}

			// Without ownerKey, owner-encrypted entities would fail
			if (this.ownerEncryptedEntities.has(elementId) && !ownerKey) {
				throw new SessionKeyNotFoundError(`Could not decrypt owner-encrypted entity: ${elementId}`)
			}

			return entity
		} else if (typeof id === "string") {
			const entity = this.entities[id]
			if (!entity) throw new NotFoundError(`Not found: ${id}`)
			return entity
		}
		throw new Error("Invalid ID")
	}

	async loadRange<T extends ListElementEntity>(
		typeRef: TypeRef<T>,
		listId: string,
		start: string,
		count: number,
		reverse: boolean,
	): Promise<T[]> {
		const entities = this.listEntities[listId] || {}
		return Object.values(entities) as T[]
	}

	async loadMultiple<T extends SomeEntity>(
		typeRef: TypeRef<T>,
		listId: string | null,
		elementIds: string[],
	): Promise<T[]> {
		// BUG: loadMultiple doesn't accept ownerKey parameter
		// So it can't decrypt owner-encrypted entities
		const results: T[] = []

		if (listId) {
			const blobEntities = this.blobEntities[listId]
			if (!blobEntities) throw new NotFoundError(`List not found: ${listId}`)

			for (const elementId of elementIds) {
				const entity = blobEntities[elementId]
				if (!entity) continue

				// This is the bug: we're checking if entity is owner-encrypted
				// but we have no ownerKey to decrypt it!
				if (this.ownerEncryptedEntities.has(elementId)) {
					// In the real code, this would result in:
					// SessionKeyNotFoundError during decryption
					throw new SessionKeyNotFoundError(
						`Failed to resolve session key for owner-encrypted entity: ${elementId}. ` +
						`The ownerKey from the parent mail object was not propagated to loadMultiple.`,
					)
				}

				results.push(entity)
			}
		} else {
			for (const elementId of elementIds) {
				const entity = this.entities[elementId]
				if (!entity) continue

				if (this.ownerEncryptedEntities.has(elementId)) {
					throw new SessionKeyNotFoundError(
						`Failed to resolve session key for owner-encrypted entity: ${elementId}`,
					)
				}

				results.push(entity)
			}
		}

		return results
	}

	async setup(): Promise<string> {
		throw new Error("Not implemented")
	}

	async setupMultiple(): Promise<string[]> {
		throw new Error("Not implemented")
	}

	async update(): Promise<void> {
		throw new Error("Not implemented")
	}

	async erase(): Promise<void> {
		throw new Error("Not implemented")
	}

	async entityEventsReceived(): Promise<any> {
		throw new Error("Not implemented")
	}
}

describe("Regression: Non-legacy mail content fails to decrypt", () => {
	let mockRestClient: BuggyEntityRestClientMock
	let entityClient: EntityClient

	beforeEach(() => {
		mockRestClient = new BuggyEntityRestClientMock()
		entityClient = new EntityClient(mockRestClient as any)
	})

	test("loadMailDetails fails to decrypt non-legacy mail MailDetailsBlob due to missing ownerKey", async () => {
		// Setup: Create a non-legacy mail
		const mail = createMail()
		mail._id = ["mailListId", "mailElementId"]
		mail.mailDetails = ["mailDetailsListId", "mailDetailsElementId"] // Non-legacy mail has mailDetails
		mail.mailDetailsDraft = null // Not a draft

		// Create the MailDetailsBlob that would be loaded
		const mailDetailsBlob = createMailDetailsBlob()
		mailDetailsBlob._id = ["mailDetailsListId", "mailDetailsElementId"]
		mailDetailsBlob.details = createMailDetails()
		mailDetailsBlob.details.body = createMailBody()
		mailDetailsBlob.details.body.text = "Test mail body"

		// Add to mock
		mockRestClient.addBlobInstance(mailDetailsBlob)
		mockRestClient.addListInstance(mail)

		// Mark the MailDetailsBlob as owner-encrypted
		// This simulates the non-legacy permission model where
		// the session key is encrypted with the owner's key
		mockRestClient.markAsOwnerEncrypted("mailDetailsElementId")

		// The bug: loadMailDetails calls loadMultiple without passing ownerKey
		// So when trying to decrypt the MailDetailsBlob, it fails
		await expect(loadMailDetails(entityClient, mail)).rejects.toThrow(SessionKeyNotFoundError)

		// Verify the error message indicates the session key resolution failed
		try {
			await loadMailDetails(entityClient, mail)
			fail("Should have thrown SessionKeyNotFoundError")
		} catch (e: any) {
			expect(e).toBeInstanceOf(SessionKeyNotFoundError)
			expect(e.message).toContain("ownerKey")
		}
	})

	test("entityClient.loadMultiple does not accept ownerKey parameter", () => {
		// This test verifies the root cause of the bug:
		// The loadMultiple method signature doesn't include an ownerKey parameter
		const loadMultipleSignature = entityClient.loadMultiple.toString()

		// The signature should show ownerKey is not available
		// Unlike load() which has it: load(..., ownerKey?: Aes128Key)
		expect(loadMultipleSignature).toContain("elementIds")
		expect(loadMultipleSignature).not.toContain("ownerKey")
	})

	test("entityClient.load() correctly accepts ownerKey parameter", () => {
		// Verify that the load() method does have ownerKey parameter
		const loadSignature = entityClient.load.toString()
		expect(loadSignature).toContain("ownerKey")
	})

	test("Demonstrates the key propagation gap between load() and loadMultiple()", async () => {
		// Setup: Create test data
		const testEntity = createMailDetailsBlob()
		testEntity._id = ["listId", "elementId"]

		mockRestClient.addBlobInstance(testEntity)
		mockRestClient.markAsOwnerEncrypted("elementId")

		const fakeOwnerKey = new Uint8Array(16) as Aes128Key

		// Scenario 1: load() with ownerKey - would succeed (has ownerKey parameter)
		// We can't call it directly here since our mock is simplified,
		// but the signature shows it accepts ownerKey
		const loadCanAcceptOwnerKey = entityClient.load.length >= 5
		expect(loadCanAcceptOwnerKey).toBe(true)

		// Scenario 2: loadMultiple() without ownerKey - fails (no ownerKey parameter)
		// This is the bug - there's no way to pass the session key
		const loadMultipleCanAcceptOwnerKey = entityClient.loadMultiple.length >= 4
		expect(loadMultipleCanAcceptOwnerKey).toBe(false) // The parameter is missing!

		// Therefore, loadMultiple() cannot decrypt owner-encrypted entities
		await expect(
			entityClient.loadMultiple(MailDetailsBlobTypeRef, "listId", ["elementId"])
		).rejects.toThrow(SessionKeyNotFoundError)
	})

	test("Issue affects InboxRuleHandler.getMailDetails()", async () => {
		// The same bug exists in InboxRuleHandler.ts:149
		// where it calls loadMultiple for MailDetailsBlob without passing ownerKey

		const mail = createMail()
		mail._id = ["mailListId", "mailElementId"]
		mail.mailDetails = ["detailsListId", "detailsElementId"]

		const mailDetailsBlob = createMailDetailsBlob()
		mailDetailsBlob._id = ["detailsListId", "detailsElementId"]

		mockRestClient.addBlobInstance(mailDetailsBlob)
		mockRestClient.markAsOwnerEncrypted("detailsElementId")

		// Simulating what InboxRuleHandler.getMailDetails does:
		// let mailDetailsBlobs = await entityClient.loadMultiple(
		//   MailDetailsBlobTypeRef, listIdPart(mailDetailsBlobId), [elementIdPart(mailDetailsBlobId)])

		await expect(
			entityClient.loadMultiple(MailDetailsBlobTypeRef, "detailsListId", ["detailsElementId"])
		).rejects.toThrow(SessionKeyNotFoundError)
	})

	test("Issue affects MailViewerViewModel.loadAttachments()", async () => {
		// Similar issue in MailViewerViewModel.ts:652
		// where it calls loadMultiple for FileTypeRef without passing ownerKey

		const attachmentElementId = "attachmentElementId"

		// In the real scenario, this would be a File entity that's owner-encrypted
		mockRestClient.markAsOwnerEncrypted(attachmentElementId)

		// Simulating: const files = await this.entityClient.loadMultiple(
		//   FileTypeRef, attachmentsListId, attachmentElementIds)

		await expect(
			entityClient.loadMultiple(MailTypeRef, "attachmentsListId", [attachmentElementId])
		).rejects.toThrow(SessionKeyNotFoundError)
	})
})

module.exports = {
	preset: 'ts-jest',
	testEnvironment: 'node',
	roots: ['<rootDir>'],
	testMatch: ['**/*.test.ts'],
	moduleNameMapper: {
		'^@tutao/tutanota-utils$': '<rootDir>/node_modules/@tutao/tutanota-utils',
	},
	transform: {
		'^.+\\.tsx?$': ['ts-jest', {
			tsconfig: {
				esModuleInterop: true,
				allowSyntheticDefaultImports: true,
				resolveJsonModule: true,
			},
		}],
	},
}

