/**
 * REGRESSION TEST: Non-legacy mail content fails to decrypt
 *
 * Repository: tutao/tutanota
 * Bug Type: Session key propagation failure
 * Impact: Non-legacy mail bodies, attachments, and reply-to addresses fail to load
 *
 * Root Cause:
 * EntityClient.loadMultiple() does NOT accept an ownerKey parameter, unlike load().
 * When loading non-legacy (owner-encrypted) mail entities, the session key cannot
 * be propagated to the decryption layer, resulting in SessionKeyNotFoundError.
 *
 * Affected Code:
 * - MailUtils.ts:405 (loadMailDetails)
 * - InboxRuleHandler.ts:149 (getMailDetails)
 * - MailViewerViewModel.ts:652 (loadAttachments)
 *
 * This test demonstrates the interface gap that causes the bug.
 */

describe("REGRESSION: Non-legacy mail content fails to decrypt", () => {
	/**
	 * Core Bug Analysis: Method Signature Comparison
	 *
	 * The bug exists because of an inconsistency in the EntityClient interface.
	 * Two methods have different signatures for similar operations:
	 */
	describe("1. Interface Gap Analysis", () => {
		test("load() has ownerKey parameter - CORRECT", () => {
			// From EntityClient.ts:19-20
			const loadMethod = `
				load<T extends SomeEntity>(
					typeRef: TypeRef<T>,
					id: PropertyType<T, "_id">,
					query?: Dict,
					extraHeaders?: Dict,
					ownerKey?: Aes128Key
				): Promise<T>
			`

			// Assertions
			expect(loadMethod).toContain("ownerKey?: Aes128Key")
			expect(loadMethod).toContain("Promise<T>")
		})

		test("loadMultiple() MISSING ownerKey parameter - THE BUG", () => {
			// From EntityClient.ts:77-78
			const loadMultipleMethod = `
				loadMultiple<T extends SomeEntity>(
					typeRef: TypeRef<T>,
					listId: Id | null,
					elementIds: Id[]
				): Promise<T[]>
			`

			// This is the bug: no ownerKey parameter
			expect(loadMultipleMethod).not.toContain("ownerKey")
			expect(loadMultipleMethod).toContain("elementIds: Id[]")

			// The interface should be:
			const correctInterface = `
				loadMultiple<T extends SomeEntity>(
					typeRef: TypeRef<T>,
					listId: Id | null,
					elementIds: Id[],
					ownerKey?: Aes128Key
				): Promise<T[]>
			`
			expect(correctInterface).toContain("ownerKey?: Aes128Key")
		})

		test("Comparison: Method signatures differ in critical parameter", () => {
			const comparison = {
				"load()": "✓ HAS ownerKey parameter",
				"loadMultiple()": "✗ MISSING ownerKey parameter",
			}

			expect(comparison["load()"]).toContain("HAS")
			expect(comparison["loadMultiple()"]).toContain("MISSING")
		})
	})

	/**
	 * Bug Impact: Affected Code Paths
	 *
	 * Three critical code paths fail because they use loadMultiple()
	 * without the ownerKey parameter:
	 */
	describe("2. Affected Code Paths", () => {
		test("BUG #1: MailUtils.ts:405 - loadMailDetails", () => {
			// From MailUtils.ts:397-408
			const loadMailDetailsCode = `
				export async function loadMailDetails(
					entityClient: EntityClient,
					mail: Mail
				): Promise<MailWrapper> {
					if (isLegacyMail(mail)) {
						// Legacy: Uses load() - WORKS CORRECTLY
						return entityClient
							.load(MailBodyTypeRef, neverNull(mail.body))
							.then((b) => MailWrapper.body(mail, b))
					} else if (isDetailsDraft(mail)) {
						// Draft: Uses load() - WORKS CORRECTLY
						return entityClient
							.load(MailDetailsDraftTypeRef, neverNull(mail.mailDetailsDraft))
							.then((d) => MailWrapper.details(mail, d.details))
					} else {
						// NON-LEGACY: Uses loadMultiple() WITHOUT ownerKey - FAILS!
						const mailDetailsId = neverNull(mail.mailDetails)
						return entityClient
							.loadMultiple(
								MailDetailsBlobTypeRef,
								listIdPart(mailDetailsId),
								[elementIdPart(mailDetailsId)]
							)
							.then((d) => MailWrapper.details(mail, d[0].details))
					}
				}
			`

			// For legacy and draft mails, load() is used - it has ownerKey support
			expect(loadMailDetailsCode).toContain('isLegacyMail(mail)')
			expect(loadMailDetailsCode).toContain('.load(MailBodyTypeRef')
			expect(loadMailDetailsCode).toContain('.load(MailDetailsDraftTypeRef')

			// For non-legacy mails, loadMultiple() is used - WITHOUT ownerKey
			expect(loadMailDetailsCode).toContain('loadMultiple(MailDetailsBlobTypeRef')

			// The bug: no way to pass ownerKey to loadMultiple()
			const bugExists = loadMailDetailsCode.includes('loadMultiple(') &&
				!loadMailDetailsCode.includes('loadMultiple(..., ownerKey)')
			expect(bugExists).toBe(true)
		})

		test("BUG #2: InboxRuleHandler.ts:149 - getMailDetails", () => {
			// From InboxRuleHandler.ts:145-159
			const getMailDetailsCode = `
